"use client";

import { useCallback, useEffect, useRef, useState } from "react";
import { Header } from "@/components/Header";
import { Toast, type ToastData } from "@/components/Toast";
import { BaseSelector } from "@/components/BaseSelector";
import { ColorantEditor, type EditorRow } from "@/components/ColorantEditor";
import { BatchPanel } from "@/components/BatchPanel";
import { ResultsPanel } from "@/components/ResultsPanel";
import { FormulaLibrary } from "@/components/FormulaLibrary";
import { SavePanel, type SaveStatus } from "@/components/SavePanel";
import { IconAlertTriangle } from "@/components/icons";
import {
  computeMix,
  isFatal,
  parseDecimal,
  MAX_BATCH_LITERS,
  type Colorant,
  type MixResult,
  type MixRowInput,
  type PaintBase,
  type VolumeUnit,
} from "@/lib/mixing";
import { sanitizeText } from "@/lib/sanitize";
import { logAnalytics } from "@/lib/analytics";
import { loadQueue, persistQueue, type Formula, type QueuedFormula } from "@/lib/formulas";

const newKey = () =>
  `row-${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 8)}`;

const emptyRows = (): EditorRow[] => [
  { key: newKey(), colorantCode: "", rate: "" },
  { key: newKey(), colorantCode: "", rate: "" },
];

export default function Page() {
  // ---- catalog ----
  const [colorants, setColorants] = useState<Colorant[]>([]);
  const [bases, setBases] = useState<PaintBase[]>([]);
  const [catalogLoading, setCatalogLoading] = useState(true);
  const [catalogError, setCatalogError] = useState<string | null>(null);

  // ---- calculator editor ----
  const [baseCode, setBaseCode] = useState("");
  const [rows, setRows] = useState<EditorRow[]>(emptyRows);
  const [errors, setErrors] = useState<Record<string, string>>({});
  const [formAlert, setFormAlert] = useState<string | null>(null);
  const [volume, setVolume] = useState("10");
  const [unit, setUnit] = useState<VolumeUnit>("L");
  const [result, setResult] = useState<MixResult | { fatal: string } | null>(null);
  const [computedAt, setComputedAt] = useState<Date | null>(null);

  // ---- formula library ----
  const [formulas, setFormulas] = useState<Formula[]>([]);
  const [formulasLoading, setFormulasLoading] = useState(true);
  const [formulasError, setFormulasError] = useState<string | null>(null);
  const [query, setQuery] = useState("");
  const [deletingId, setDeletingId] = useState<number | null>(null);

  // ---- save panel ----
  const [saveName, setSaveName] = useState("");
  const [saveNotes, setSaveNotes] = useState("");
  const [nameError, setNameError] = useState<string | null>(null);
  const [saveStatus, setSaveStatus] = useState<SaveStatus>("idle");
  const [saveMessage, setSaveMessage] = useState<string | null>(null);

  // ---- connectivity / offline queue ----
  const [online, setOnline] = useState(true);
  const [syncing, setSyncing] = useState(false);
  const [queuedCount, setQueuedCount] = useState(0);

  const [toast, setToast] = useState<ToastData | null>(null);
  const [today, setToday] = useState("");

  const calcRef = useRef<HTMLFormElement | null>(null);
  const queryRef = useRef("");
  const flushingRef = useRef(false);
  const catalogRequest = useRef<AbortController | null>(null);
  const formulaRequest = useRef<AbortController | null>(null);

  queryRef.current = query;

  const showToast = useCallback((kind: ToastData["kind"], message: string) => {
    setToast({ id: Date.now(), kind, message });
  }, []);

  // ---- catalog ----
  const fetchCatalog = useCallback(async () => {
    catalogRequest.current?.abort();
    const controller = new AbortController();
    catalogRequest.current = controller;
    setCatalogLoading(true);
    setCatalogError(null);
    try {
      const res = await fetch("/api/catalog", { signal: controller.signal });
      if (!res.ok) throw new Error("catalog request failed");
      const data = (await res.json()) as { bases: PaintBase[]; colorants: Colorant[] };
      setBases(data.bases);
      setColorants(data.colorants);
      setBaseCode((prev) =>
        data.bases.some((b) => b.code === prev) ? prev : (data.bases[0]?.code ?? ""),
      );
    } catch (err) {
      if ((err as Error).name === "AbortError") return;
      setCatalogError(
        "The colourant catalog could not be loaded. Check the connection, then retry.",
      );
    } finally {
      if (catalogRequest.current === controller) setCatalogLoading(false);
    }
  }, []);

  useEffect(() => {
    void fetchCatalog();
    return () => catalogRequest.current?.abort();
  }, [fetchCatalog]);

  // ---- formulas ----
  const fetchFormulas = useCallback(async (q: string) => {
    formulaRequest.current?.abort();
    const controller = new AbortController();
    formulaRequest.current = controller;
    setFormulasLoading(true);
    setFormulasError(null);
    try {
      const url = q.trim() ? `/api/formulas?q=${encodeURIComponent(q.trim())}` : "/api/formulas";
      const res = await fetch(url, { signal: controller.signal });
      if (!res.ok) {
        const body = (await res.json().catch(() => null)) as { error?: string } | null;
        throw new Error(body?.error ?? "formula request failed");
      }
      const data = (await res.json()) as { formulas: Formula[] };
      setFormulas(data.formulas);
    } catch (err) {
      if ((err as Error).name === "AbortError") return;
      setFormulasError(
        "Saved formulas could not be loaded. Check the connection, then retry.",
      );
    } finally {
      if (formulaRequest.current === controller) setFormulasLoading(false);
    }
  }, []);

  useEffect(() => {
    const handle = setTimeout(() => {
      void fetchFormulas(queryRef.current);
    }, 250);
    return () => clearTimeout(handle);
  }, [query, fetchFormulas]);

  // ---- offline queue sync ----
  const flushQueue = useCallback(async () => {
    if (flushingRef.current) return;
    const queue = loadQueue();
    setQueuedCount(queue.length);
    if (queue.length === 0) return;

    flushingRef.current = true;
    setSyncing(true);
    let synced = 0;
    const remaining: QueuedFormula[] = [];

    for (const item of queue) {
      try {
        const res = await fetch("/api/formulas", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify(item),
        });
        if (res.ok) {
          synced += 1;
        } else {
          remaining.push(item);
        }
      } catch {
        remaining.push(item);
      }
    }

    persistQueue(remaining);
    setQueuedCount(remaining.length);
    setSyncing(false);
    flushingRef.current = false;

    if (synced > 0) {
      showToast(
        "success",
        `${synced} queued formula${synced === 1 ? "" : "s"} synced to the server.`,
      );
      void fetchFormulas(queryRef.current);
      logAnalytics("Offline queue synced", { count: synced });
    }
  }, [fetchFormulas, showToast]);

  // ---- connectivity listeners ----
  useEffect(() => {
    const handleOnline = () => {
      setOnline(true);
      void flushQueue();
    };
    const handleOffline = () => setOnline(false);
    setOnline(navigator.onLine);
    window.addEventListener("online", handleOnline);
    window.addEventListener("offline", handleOffline);
    return () => {
      window.removeEventListener("online", handleOnline);
      window.removeEventListener("offline", handleOffline);
    };
  }, [flushQueue]);

  useEffect(() => {
    setQueuedCount(loadQueue().length);
    void flushQueue();
  }, [flushQueue]);

  useEffect(() => {
    setToday(
      new Date().toLocaleDateString("en-GB", {
        weekday: "short",
        day: "2-digit",
        month: "short",
        year: "numeric",
      }),
    );
  }, []);

  // ---- toast auto-dismiss ----
  useEffect(() => {
    if (!toast) return;
    const handle = setTimeout(() => setToast(null), 4500);
    return () => clearTimeout(handle);
  }, [toast]);

  // ---- editor handlers ----
  const handleRowChange = useCallback((key: string, patch: Partial<EditorRow>) => {
    if (patch.rate !== undefined) {
      patch = { ...patch, rate: patch.rate.replace(/[^\d.]/g, "").slice(0, 8) };
    }
    setRows((prev) => prev.map((row) => (row.key === key ? { ...row, ...patch } : row)));
    setErrors((prev) => {
      const next = { ...prev };
      delete next[`${key}:colorant`];
      delete next[`${key}:rate`];
      return next;
    });
  }, []);

  const handleRowAdd = useCallback(() => {
    setRows((prev) => {
      if (prev.length >= 12) {
        showToast("info", "A batch supports a maximum of 12 colourant rows.");
        return prev;
      }
      logAnalytics("Colorant row added");
      return [...prev, { key: newKey(), colorantCode: "", rate: "" }];
    });
  }, [showToast]);

  const handleRowRemove = useCallback((key: string) => {
    setRows((prev) => {
      const next = prev.filter((row) => row.key !== key);
      return next.length === 0 ? [{ key: newKey(), colorantCode: "", rate: "" }] : next;
    });
    setErrors((prev) => {
      const next = { ...prev };
      delete next[`${key}:colorant`];
      delete next[`${key}:rate`];
      return next;
    });
  }, []);

  const collectValidRows = useCallback((): {
    mixRows: MixRowInput[];
    hasDuplicates: boolean;
  } => {
    const mixRows: MixRowInput[] = [];
    const seen = new Set<string>();
    let hasDuplicates = false;
    for (const row of rows) {
      const rate = parseDecimal(row.rate);
      if (!row.colorantCode || rate === null || rate <= 0) continue;
      if (seen.has(row.colorantCode)) {
        hasDuplicates = true;
        continue;
      }
      seen.add(row.colorantCode);
      mixRows.push({ colorantCode: row.colorantCode, mlPerLiter: rate });
    }
    return { mixRows, hasDuplicates };
  }, [rows]);

  // ---- calculate ----
  const handleCalculate = useCallback(
    (event: React.FormEvent<HTMLFormElement>) => {
      event.preventDefault();
      const nextErrors: Record<string, string> = {};
      setFormAlert(null);

      const parsedVolume = parseDecimal(volume);
      if (parsedVolume === null) {
        nextErrors.volume = "Enter a numeric batch volume.";
      } else if (parsedVolume <= 0) {
        nextErrors.volume = "Batch volume must be greater than zero.";
      } else if (parsedVolume > MAX_BATCH_LITERS) {
        nextErrors.volume = `Batch volume cannot exceed ${MAX_BATCH_LITERS} L per batch.`;
      }

      const mixRows: MixRowInput[] = [];
      const seen = new Set<string>();
      for (const row of rows) {
        const hasColorant = row.colorantCode !== "";
        const hasRate = row.rate.trim() !== "";
        if (!hasColorant && !hasRate) continue;

        if (!hasColorant) {
          nextErrors[`${row.key}:colorant`] = "Select a colourant.";
        }
        let rate: number | null = null;
        if (!hasRate) {
          nextErrors[`${row.key}:rate`] = "Enter a rate.";
        } else {
          rate = parseDecimal(row.rate);
          if (rate === null || rate <= 0) {
            nextErrors[`${row.key}:rate`] = "Rate must be a number above zero.";
            rate = null;
          } else if (rate > 600) {
            nextErrors[`${row.key}:rate`] = "Rate cannot exceed 600 ml/L.";
            rate = null;
          }
        }

        if (hasColorant && rate !== null) {
          if (seen.has(row.colorantCode)) {
            nextErrors[`${row.key}:colorant`] = "Duplicate colourant — already dosed above.";
          } else {
            seen.add(row.colorantCode);
            mixRows.push({ colorantCode: row.colorantCode, mlPerLiter: rate });
          }
        }
      }

      if (Object.keys(nextErrors).length > 0) {
        setErrors(nextErrors);
        setFormAlert("Some fields need attention before the batch can be calculated.");
        return;
      }
      if (mixRows.length === 0) {
        setErrors({});
        setFormAlert("Add at least one colourant with a rate above zero.");
        return;
      }

      const base = bases.find((b) => b.code === baseCode) ?? bases[0];
      if (!base || parsedVolume === null) {
        setFormAlert("The colourant catalog is unavailable. Retry loading, then calculate again.");
        return;
      }

      const mix = computeMix({ base, rows: mixRows, volume: parsedVolume, unit, colorants });
      if (isFatal(mix)) {
        setResult(mix);
        setComputedAt(new Date());
        return;
      }

      setResult(mix);
      setComputedAt(new Date());
      logAnalytics("Mix calculated", {
        base: base.name,
        colorantRows: mixRows.length,
        volume: parsedVolume,
        unit,
        loadPct: Math.round(mix.loadPct * 10) / 10,
      });
    },
    [volume, rows, bases, baseCode, unit, colorants],
  );

  const handleReset = useCallback(() => {
    setRows(emptyRows());
    setVolume("10");
    setUnit("L");
    setErrors({});
    setFormAlert(null);
    setResult(null);
    setComputedAt(null);
    logAnalytics("Calculator reset");
    showToast("info", "Calculator reset to a blank batch.");
  }, [showToast]);

  // ---- library handlers ----
  const handleLoadFormula = useCallback(
    (formula: Formula) => {
      setBaseCode(formula.baseCode);
      setRows(
        formula.items.length > 0
          ? formula.items.map((item) => ({
              key: newKey(),
              colorantCode: item.colorantCode,
              rate: String(item.mlPerLiter),
            }))
          : emptyRows(),
      );
      setErrors({});
      setFormAlert(null);
      setResult(null);
      setComputedAt(null);
      logAnalytics("Formula loaded", { id: formula.id, name: formula.name });
      showToast("info", `"${formula.name}" loaded — choose Calculate batch to produce the report.`);
      calcRef.current?.scrollIntoView({ behavior: "smooth", block: "start" });
    },
    [showToast],
  );

  const handleDeleteFormula = useCallback(
    async (id: number) => {
      if (deletingId !== id) {
        setDeletingId(id);
        return;
      }
      try {
        const res = await fetch(`/api/formulas/${id}`, { method: "DELETE" });
        const body = (await res.json().catch(() => null)) as { error?: string } | null;
        if (!res.ok) {
          showToast("error", body?.error ?? "The formula could not be deleted.");
          setDeletingId(null);
          return;
        }
        setFormulas((prev) => prev.filter((f) => f.id !== id));
        showToast("success", "Formula deleted from the library.");
        logAnalytics("Formula deleted", { id });
      } catch {
        showToast("error", "Connection lost — the formula was not deleted.");
      } finally {
        setDeletingId(null);
      }
    },
    [deletingId, showToast],
  );

  // ---- save handler ----
  const handleSave = useCallback(async () => {
    const cleanName = sanitizeText(saveName, 60);
    if (cleanName.length < 2) {
      setNameError("Formula name needs at least 2 characters.");
      return;
    }
    setNameError(null);

    const { mixRows, hasDuplicates } = collectValidRows();
    if (hasDuplicates) {
      showToast("error", "Remove duplicate colourant rows before saving.");
      return;
    }
    if (mixRows.length === 0) {
      showToast("error", "Add at least one colourant row with a rate before saving.");
      return;
    }
    if (!baseCode) {
      showToast("error", "Select a base paint before saving.");
      return;
    }

    const payload = {
      name: cleanName,
      baseCode,
      notes: sanitizeText(saveNotes, 240),
      items: mixRows,
    };

    setSaveStatus("saving");
    setSaveMessage(null);
    try {
      const res = await fetch("/api/formulas", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(payload),
      });
      const body = (await res.json().catch(() => null)) as { error?: string } | null;
      if (!res.ok) {
        setSaveStatus("error");
        setSaveMessage(body?.error ?? "The formula could not be saved. Retry when ready.");
        return;
      }
      setSaveStatus("success");
      setSaveMessage(`"${cleanName}" saved to the formula library.`);
      setSaveName("");
      setSaveNotes("");
      void fetchFormulas(queryRef.current);
      logAnalytics("Formula saved", { name: cleanName, colorantRows: mixRows.length });
    } catch {
      // Network failure: queue locally so the store never loses work.
      const queue = loadQueue();
      queue.push(payload);
      persistQueue(queue);
      setQueuedCount(queue.length);
      setSaveStatus("success");
      setSaveMessage("Connection down — the formula was queued on this device and will sync automatically.");
      setSaveName("");
      setSaveNotes("");
      logAnalytics("Formula queued offline", { name: cleanName });
    }
  }, [saveName, saveNotes, baseCode, collectValidRows, fetchFormulas, showToast]);

  const catalogUnavailable = Boolean(catalogError);

  return (
    <div className="flex min-h-screen flex-col">
      <Header online={online} syncing={syncing} queuedCount={queuedCount} />

      <main id="main-content" className="mx-auto w-full max-w-[1280px] flex-1 px-4 py-8 sm:px-8">
        <div className="no-print mb-8 flex flex-wrap items-end justify-between gap-6">
          <div>
            <p className="kicker">Colour dispensing · Floor tool</p>
            <h1 className="mt-2 font-display text-4xl font-extrabold tracking-tight text-ink-950 sm:text-[44px]">
              Batch Calculator
            </h1>
            <p className="mt-3 max-w-xl text-[15px] leading-relaxed text-ink-600">
              Dose colorants against a base paint, verify the colourant load, and print a
              dispensing ticket. Saved formulas persist to the store database.
            </p>
          </div>
          <div className="card border-l-4 border-l-ink-900 px-5 py-4">
            <p className="font-mono text-[10px] uppercase tracking-[0.18em] text-ink-400">
              Station
            </p>
            <p className="mt-1 font-mono text-sm font-semibold text-ink-900">STN-01 · Dispensing</p>
            <p className="mt-0.5 font-mono text-xs text-ink-500">{today || "—"}</p>
          </div>
        </div>

        <div className="grid items-start gap-8 lg:grid-cols-[minmax(0,1fr)_400px]">
          {/* ---------------- calculator column ---------------- */}
          <div className="min-w-0">
            {catalogError && (
              <div
                role="alert"
                className="mb-6 flex flex-wrap items-center justify-between gap-4 rounded-md border border-danger-100 bg-danger-50 p-4"
              >
                <p className="flex items-start gap-2 text-sm leading-relaxed text-danger-700">
                  <IconAlertTriangle className="mt-0.5 h-4 w-4 shrink-0 text-danger-600" />
                  {catalogError}
                </p>
                <button type="button" onClick={() => void fetchCatalog()} className="btn btn-secondary btn-sm">
                  Retry
                </button>
              </div>
            )}

            <form
              ref={calcRef}
              onSubmit={handleCalculate}
              noValidate
              className="card no-print scroll-mt-24 p-6 sm:p-8"
              aria-label="Paint mixing calculator form"
            >
              <div className="space-y-8">
                <BaseSelector
                  bases={bases}
                  loading={catalogLoading}
                  selected={baseCode}
                  onSelect={setBaseCode}
                  disabled={catalogUnavailable}
                />

                <ColorantEditor
                  rows={rows}
                  colorants={colorants}
                  catalogLoading={catalogLoading}
                  errors={errors}
                  disabled={catalogUnavailable}
                  onRowChange={handleRowChange}
                  onRowAdd={handleRowAdd}
                  onRowRemove={handleRowRemove}
                />

                <BatchPanel
                  volume={volume}
                  unit={unit}
                  error={errors.volume}
                  disabled={catalogUnavailable}
                  onVolumeChange={(value) => {
                    setVolume(value.replace(/[^\d.]/g, "").slice(0, 8));
                    setErrors((prev) => {
                      const next = { ...prev };
                      delete next.volume;
                      return next;
                    });
                  }}
                  onUnitChange={setUnit}
                />
              </div>

              {formAlert && (
                <p
                  role="alert"
                  className="mt-6 flex items-start gap-2 rounded-md border border-danger-100 bg-danger-50 p-3 text-sm font-medium text-danger-700"
                >
                  <IconAlertTriangle className="mt-0.5 h-4 w-4 shrink-0 text-danger-600" />
                  {formAlert}
                </p>
              )}

              <div className="mt-8 flex flex-wrap items-center gap-3 border-t border-ink-100 pt-6">
                <button type="submit" className="btn btn-primary" disabled={catalogUnavailable}>
                  Calculate batch
                </button>
                <button type="button" onClick={handleReset} className="btn btn-secondary">
                  Reset
                </button>
                <p className="ml-auto font-mono text-[11px] uppercase tracking-[0.1em] text-ink-400">
                  Results update on demand
                </p>
              </div>
            </form>

            <ResultsPanel result={result} computedAt={computedAt} />
          </div>

          {/* ---------------- library column ---------------- */}
          <div className="no-print space-y-6 lg:sticky lg:top-24">
            <FormulaLibrary
              formulas={formulas}
              bases={bases}
              loading={formulasLoading}
              error={formulasError}
              query={query}
              deletingId={deletingId}
              onQueryChange={(value) => setQuery(sanitizeText(value, 80))}
              onRetry={() => void fetchFormulas(queryRef.current)}
              onLoad={handleLoadFormula}
              onDelete={(id) => void handleDeleteFormula(id)}
            />
            <SavePanel
              name={saveName}
              notes={saveNotes}
              nameError={nameError}
              status={saveStatus}
              statusMessage={saveMessage}
              online={online}
              queuedCount={queuedCount}
              disabled={catalogUnavailable}
              onNameChange={(value) => {
                setSaveName(sanitizeText(value, 60));
                if (nameError) setNameError(null);
              }}
              onNotesChange={(value) => setSaveNotes(sanitizeText(value, 240))}
              onSave={() => void handleSave()}
            />
          </div>
        </div>
      </main>

      <footer className="no-print border-t border-ink-200 bg-white/70">
        <div className="mx-auto flex max-w-[1280px] flex-col justify-between gap-2 px-4 py-6 font-mono text-[11px] uppercase tracking-[0.1em] text-ink-400 sm:flex-row sm:px-8">
          <p>MixStation Pro v1.0.0 · Internal dispensing tool</p>
          <p>Telemetry simulated to console · No customer data collected</p>
        </div>
      </footer>

      <Toast toast={toast} onDismiss={() => setToast(null)} />
    </div>
  );
}
