import type { PaintBase } from "@/lib/mixing";
import type { Formula } from "@/lib/formulas";
import { IconSearch, IconSync, IconTrash } from "@/components/icons";

interface FormulaLibraryProps {
  formulas: Formula[];
  bases: PaintBase[];
  loading: boolean;
  error: string | null;
  query: string;
  deletingId: number | null;
  onQueryChange: (value: string) => void;
  onRetry: () => void;
  onLoad: (formula: Formula) => void;
  onDelete: (id: number) => void;
}

export function FormulaLibrary({
  formulas,
  bases,
  loading,
  error,
  query,
  deletingId,
  onQueryChange,
  onRetry,
  onLoad,
  onDelete,
}: FormulaLibraryProps) {
  const baseName = (code: string) => bases.find((b) => b.code === code)?.name ?? code;

  return (
    <section aria-labelledby="library-heading" className="card no-print overflow-hidden">
      <div className="flex items-center justify-between gap-4 border-b border-ink-200 px-5 py-4">
        <div>
          <h2 id="library-heading" className="kicker">
            Formula library
          </h2>
          {!loading && !error && (
            <p className="mt-1 font-mono text-[11px] text-ink-400">
              {formulas.length} {formulas.length === 1 ? "formula" : "formulas"}
            </p>
          )}
        </div>
      </div>

      <div className="p-5">
        <div className="relative">
          <label htmlFor="formula-search" className="sr-only">
            Search formulas by name
          </label>
          <IconSearch className="pointer-events-none absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-ink-400" />
          <input
            id="formula-search"
            type="search"
            placeholder="Search formulas…"
            className="input pl-9"
            value={query}
            onChange={(e) => onQueryChange(e.target.value)}
          />
        </div>

        <div className="mt-4">
          {loading ? (
            <div className="space-y-3" aria-hidden="true">
              {[0, 1, 2, 3].map((i) => (
                <div key={i} className="skeleton h-16" />
              ))}
            </div>
          ) : error ? (
            <div role="alert" className="rounded-md border border-danger-100 bg-danger-50 p-4">
              <p className="text-sm leading-relaxed text-danger-700">{error}</p>
              <button type="button" onClick={onRetry} className="btn btn-secondary btn-sm mt-3">
                <IconSync className="h-3.5 w-3.5" />
                Retry
              </button>
            </div>
          ) : formulas.length === 0 ? (
            <div className="rounded-md border border-dashed border-ink-300 p-6 text-center">
              <p className="text-sm font-semibold text-ink-800">
                {query ? `No formulas match "${query}"` : "No formulas available"}
              </p>
              <p className="mx-auto mt-1 max-w-[240px] text-xs leading-relaxed text-ink-500">
                {query
                  ? "Try a different colour name, or clear the search to browse everything."
                  : "Standard formulas appear here once the server is reachable."}
              </p>
              {query && (
                <button
                  type="button"
                  onClick={() => onQueryChange("")}
                  className="btn btn-secondary btn-sm mt-3"
                >
                  Clear search
                </button>
              )}
            </div>
          ) : (
            <ul className="max-h-[430px] divide-y divide-ink-100 overflow-y-auto pr-1">
              {formulas.map((formula) => {
                const totalRate = formula.items.reduce((sum, i) => sum + i.mlPerLiter, 0);
                const confirming = deletingId === formula.id;
                return (
                  <li key={formula.id} className="group py-4 first:pt-1 last:pb-1">
                    <div className="flex items-start justify-between gap-3">
                      <div className="min-w-0">
                        <div className="flex flex-wrap items-center gap-2">
                          <h3 className="font-display text-[15px] font-bold leading-tight text-ink-900">
                            {formula.name}
                          </h3>
                          <span
                            className={`chip ${
                              formula.isPreset
                                ? "bg-ink-900 text-white"
                                : "border border-ink-300 bg-white text-ink-600"
                            }`}
                          >
                            {formula.isPreset ? "Standard" : "Custom"}
                          </span>
                        </div>
                        <p className="mt-1 font-mono text-[11px] text-ink-500">
                          {baseName(formula.baseCode)} · {formula.items.length} colorant
                          {formula.items.length === 1 ? "" : "s"} ·{" "}
                          {new Intl.NumberFormat("en-US", { maximumFractionDigits: 1 }).format(totalRate)} ml/L
                        </p>
                        {formula.notes && (
                          <p className="mt-1 line-clamp-1 text-xs italic text-ink-500">
                            {formula.notes}
                          </p>
                        )}
                      </div>
                    </div>

                    <div className="mt-3 flex items-center gap-2">
                      <button
                        type="button"
                        onClick={() => onLoad(formula)}
                        className="btn btn-secondary btn-sm flex-1"
                      >
                        Load into calculator
                      </button>
                      {!formula.isPreset &&
                        (confirming ? (
                          <button
                            type="button"
                            onClick={() => onDelete(formula.id)}
                            className="btn btn-sm bg-danger-600 text-white hover:bg-danger-700"
                          >
                            Confirm
                          </button>
                        ) : (
                          <button
                            type="button"
                            onClick={() => onDelete(formula.id)}
                            aria-label={`Delete formula ${formula.name}`}
                            className="btn btn-ghost-danger"
                          >
                            <IconTrash className="h-4 w-4" />
                          </button>
                        ))}
                    </div>
                  </li>
                );
              })}
            </ul>
          )}
        </div>
      </div>
    </section>
  );
}
