import type { Colorant } from "@/lib/mixing";
import { IconAlertTriangle, IconPlus, IconTrash } from "@/components/icons";

export interface EditorRow {
  key: string;
  colorantCode: string;
  rate: string;
}

interface ColorantEditorProps {
  rows: EditorRow[];
  colorants: Colorant[];
  catalogLoading: boolean;
  errors: Record<string, string>;
  disabled: boolean;
  onRowChange: (key: string, patch: Partial<EditorRow>) => void;
  onRowAdd: () => void;
  onRowRemove: (key: string) => void;
}

export function ColorantEditor({
  rows,
  colorants,
  catalogLoading,
  errors,
  disabled,
  onRowChange,
  onRowAdd,
  onRowRemove,
}: ColorantEditorProps) {
  return (
    <fieldset disabled={disabled} className="min-w-0">
      <legend className="kicker mb-1">02 · Colourant additions</legend>
      <p className="mb-4 text-xs leading-relaxed text-ink-500">
        Rates are millilitres of colorant per litre of finished batch.
      </p>

      {catalogLoading ? (
        <div className="space-y-3" aria-hidden="true">
          {[0, 1, 2].map((i) => (
            <div key={i} className="skeleton h-[46px]" />
          ))}
        </div>
      ) : (
        <>
          <div
            aria-hidden="true"
            className="mb-2 hidden grid-cols-[2rem_minmax(0,1fr)_9.5rem_2.5rem] gap-3 sm:grid"
          >
            <span className="text-[11px] font-semibold uppercase tracking-wide text-ink-400">#</span>
            <span className="text-[11px] font-semibold uppercase tracking-wide text-ink-400">
              Colourant
            </span>
            <span className="text-[11px] font-semibold uppercase tracking-wide text-ink-400">
              Rate ml/L
            </span>
            <span />
          </div>

          <div className="space-y-3">
            {rows.map((row, index) => {
              const colorantError = errors[`${row.key}:colorant`];
              const rateError = errors[`${row.key}:rate`];
              return (
                <div
                  key={row.key}
                  className="row-enter grid grid-cols-[2rem_minmax(0,1fr)_9.5rem_2.5rem] items-start gap-3"
                >
                  <span
                    aria-hidden="true"
                    className="pt-[11px] text-center font-mono text-xs font-medium text-ink-400"
                  >
                    {String(index + 1).padStart(2, "0")}
                  </span>

                  <div className="min-w-0">
                    <label htmlFor={`colorant-${row.key}`} className="sr-only">
                      Colourant for row {index + 1}
                    </label>
                    <select
                      id={`colorant-${row.key}`}
                      className={`input select ${colorantError ? "input-invalid" : ""}`}
                      value={row.colorantCode}
                      onChange={(e) => onRowChange(row.key, { colorantCode: e.target.value })}
                      aria-invalid={colorantError ? true : undefined}
                      aria-describedby={colorantError ? `colorant-${row.key}-error` : undefined}
                    >
                      <option value="">Select colourant…</option>
                      {colorants.map((c) => (
                        <option key={c.code} value={c.code}>
                          {c.code} · {c.name}
                        </option>
                      ))}
                    </select>
                    {colorantError && (
                      <p id={`colorant-${row.key}-error`} className="field-error">
                        <IconAlertTriangle className="mt-px h-3 w-3 shrink-0" />
                        {colorantError}
                      </p>
                    )}
                  </div>

                  <div className="min-w-0">
                    <label htmlFor={`rate-${row.key}`} className="sr-only">
                      Rate for row {index + 1}, millilitres per litre
                    </label>
                    <div className="relative">
                      <input
                        id={`rate-${row.key}`}
                        type="text"
                        inputMode="decimal"
                        autoComplete="off"
                        placeholder="0.0"
                        className={`input pr-12 text-right font-mono ${rateError ? "input-invalid" : ""}`}
                        value={row.rate}
                        onChange={(e) => onRowChange(row.key, { rate: e.target.value })}
                        aria-invalid={rateError ? true : undefined}
                        aria-describedby={rateError ? `rate-${row.key}-error` : undefined}
                      />
                      <span
                        aria-hidden="true"
                        className="pointer-events-none absolute inset-y-0 right-3 flex items-center font-mono text-[11px] text-ink-400"
                      >
                        ml/L
                      </span>
                    </div>
                    {rateError && (
                      <p id={`rate-${row.key}-error`} className="field-error">
                        <IconAlertTriangle className="mt-px h-3 w-3 shrink-0" />
                        {rateError}
                      </p>
                    )}
                  </div>

                  <button
                    type="button"
                    onClick={() => onRowRemove(row.key)}
                    aria-label={`Remove colourant row ${index + 1}`}
                    className="btn-ghost-danger btn mt-[3px] rounded"
                  >
                    <IconTrash className="h-4 w-4" />
                  </button>
                </div>
              );
            })}
          </div>

          <button
            type="button"
            onClick={onRowAdd}
            className="mt-4 flex w-full items-center justify-center gap-2 rounded-md border border-dashed border-ink-300 px-4 py-3 font-display text-[13px] font-semibold text-ink-600 transition-colors hover:border-ink-600 hover:bg-ink-50 hover:text-ink-900 focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-ink-900"
          >
            <IconPlus className="h-4 w-4" />
            Add colourant row
          </button>
        </>
      )}
    </fieldset>
  );
}
