import type { PaintBase } from "@/lib/mixing";
import { IconCheck } from "@/components/icons";

interface BaseSelectorProps {
  bases: PaintBase[];
  loading: boolean;
  selected: string;
  onSelect: (code: string) => void;
  disabled: boolean;
}

export function BaseSelector({ bases, loading, selected, onSelect, disabled }: BaseSelectorProps) {
  return (
    <fieldset disabled={disabled} className="min-w-0">
      <legend className="kicker mb-3">01 · Base paint</legend>

      {loading ? (
        <div className="grid gap-3 sm:grid-cols-2" aria-hidden="true">
          {[0, 1, 2, 3].map((i) => (
            <div key={i} className="skeleton h-[104px]" />
          ))}
        </div>
      ) : (
        <div className="grid gap-3 sm:grid-cols-2">
          {bases.map((base) => {
            const isSelected = selected === base.code;
            return (
              <label
                key={base.code}
                className={`relative flex cursor-pointer flex-col gap-1 rounded-lg border-2 p-4 transition-all duration-150 ${
                  isSelected
                    ? "border-ink-900 bg-ink-50 shadow-[0_2px_8px_rgba(14,24,38,0.12)]"
                    : "border-ink-200 bg-white hover:border-ink-400 hover:shadow-sm"
                }`}
              >
                <input
                  type="radio"
                  name="base-paint"
                  value={base.code}
                  checked={isSelected}
                  onChange={() => onSelect(base.code)}
                  className="peer sr-only"
                />
                <span className="pointer-events-none absolute inset-0 rounded-lg outline-2 outline-offset-2 outline-ink-900 peer-focus-visible:outline" />
                <span className="flex items-center justify-between gap-2 pr-6">
                  <span className="font-display text-[15px] font-bold text-ink-900">
                    {base.name}
                  </span>
                  <span className="chip border border-ink-200 bg-white text-ink-500">
                    {base.code}
                  </span>
                </span>
                <span className="text-xs leading-relaxed text-ink-600">{base.description}</span>
                <span className="mt-1 font-mono text-[11px] font-medium uppercase tracking-[0.08em] text-ink-500">
                  Max colourant load {base.maxLoadPct}%
                </span>
                {isSelected && (
                  <span
                    aria-hidden="true"
                    className="absolute right-3 top-3 grid h-5 w-5 place-items-center rounded-full bg-ink-900 text-white"
                  >
                    <IconCheck className="h-3 w-3" />
                  </span>
                )}
              </label>
            );
          })}
        </div>
      )}
      {!loading && bases.length === 0 && !disabled && (
        <p className="rounded border border-dashed border-ink-300 p-4 text-sm text-ink-500">
          No base paints available. Contact your system administrator.
        </p>
      )}
    </fieldset>
  );
}
